"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["336464"],{458531(i){i.exports=JSON.parse('{"tag":{"label":"fishing","permalink":"/dst-api-webdocs/docs/tags/fishing","allTagsPath":"/dst-api-webdocs/docs/tags","count":36,"items":[{"id":"game-scripts/prefabs/chum","title":"Chum","description":"A throwable fishing bait item that spawns chum or a green splash effect depending on terrain, and creates an AOE when thrown into ocean tiles.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/chum"},{"id":"game-scripts/prefabs/chum_aoe","title":"Chum Aoe","description":"Spawns and manages a temporary chum cloud that periodically drops chum pieces and attempts to attract fish schools in ocean areas.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/chum_aoe"},{"id":"game-scripts/components/fishable","title":"Fishable","description":"Manages a pool of fish that can be caught via fishing mechanics, including respawning, freezing states, and hooking/release logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/fishable"},{"id":"game-scripts/components/fishingnet","title":"Fishingnet","description":"Manages the casting of a fishing net by spawning and configuring a visualizer prefab to handle the animation and trajectory.","permalink":"/dst-api-webdocs/docs/game-scripts/components/fishingnet"},{"id":"game-scripts/components/fishingnetvisualizer","title":"Fishingnetvisualizer","description":"Manages visual behavior and logic for a fishing net entity during casting, opening, retrieving, and final pickup phases.","permalink":"/dst-api-webdocs/docs/game-scripts/components/fishingnetvisualizer"},{"id":"game-scripts/components/fishingrod","title":"Fishingrod","description":"Manages the fishing mechanic for a fishing rod, including casting, nibbling, strain, and reeling interactions with a fishable entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/fishingrod"},{"id":"game-scripts/prefabs/fishingrod","title":"Fishingrod","description":"A multi-use tool item that allows characters to fish, deals damage in combat, and handles visual and functional behavior when equipped or used.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fishingrod"},{"id":"game-scripts/components/fishingrod_replica","title":"Fishingrod Replica","description":"Manages networked state for a fishing rod entity, tracking hooked and caught fish across the client-server boundary.","permalink":"/dst-api-webdocs/docs/game-scripts/components/fishingrod_replica"},{"id":"game-scripts/prefabs/hermitcrab","title":"Hermitcrab","description":"This prefab defines the Hermit Crab (Pearl) NPC with friendship progression, trading mechanics, island decoration complaints, reward distribution, fishing activities, seasonal behaviors, and tea shop interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermitcrab"},{"id":"game-scripts/prefabs/ocean_trawler","title":"Ocean Trawler","description":"A deployable water-based fishing structure that catches and stores fish, with state-aware perish rate scaling and overflow fish release on destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ocean_trawler"},{"id":"game-scripts/prefabs/oceanfish","title":"Oceanfish","description":"Generates both underwater swimming fish entities and their corresponding inventory item versions used in ocean fishing and cooking, including lifecycle management, prey behavior, and fire-suppression capabilities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanfish"},{"id":"game-scripts/components/oceanfishable","title":"Oceanfishable","description":"Manages the fishable state and behavior of ocean creatures when interacting with fishing rods, including stamina-based struggle mechanics and movement speed adjustments based on line tension.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanfishable"},{"id":"game-scripts/prefabs/oceanfishableflotsam","title":"Oceanfishableflotsam","description":"Represents a floating object in the ocean that can be caught with fishing rods and later fished up for loot or salvaged with a winch.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanfishableflotsam"},{"id":"game-scripts/prefabs/oceanfishdef","title":"Oceanfishdef","description":"Defines static configuration data for ocean fish species, including behavior, loot, diet, and school spawning weights.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanfishdef"},{"id":"game-scripts/prefabs/oceanfishingbobber","title":"Oceanfishingbobber","description":"Defines prefabs for ocean fishing bobbers used in the Turn of the Tides fishing system, including projectile, floater, and inventory item variants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanfishingbobber"},{"id":"game-scripts/components/oceanfishinghook","title":"Oceanfishinghook","description":"Manages fishing lure behavior and fish attraction mechanics in the ocean, including charm calculation, interest tracking, and reel-based modifiers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanfishinghook"},{"id":"game-scripts/prefabs/oceanfishinglure","title":"Oceanfishinglure","description":"Generates ocean fishing lure prefabs with configurable appearance, data, and behavior for use in the Ocean Fishing subsystem.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanfishinglure"},{"id":"game-scripts/components/oceanfishingrod","title":"Oceanfishingrod","description":"Manages the ocean fishing rod\'s casting, targeting, tension tracking, and fish capture logic, acting as the central controller for ocean fishing interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanfishingrod"},{"id":"game-scripts/prefabs/oceanfishingrod","title":"Oceanfishingrod","description":"Implements the ocean fishing rod item, managing tackle slots, reticule targeting, and fishing state transitions in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanfishingrod"},{"id":"game-scripts/components/oceanfishingrod_replica","title":"Oceanfishingrod Replica","description":"Manages networked state for the ocean fishing rod, including hook target, line tension level, and maximum cast distance.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanfishingrod_replica"},{"id":"game-scripts/components/oceanfishingtackle","title":"Oceanfishingtackle","description":"Manages casting data and lure configuration for ocean fishing mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanfishingtackle"},{"id":"game-scripts/components/oceantrawler","title":"Oceantrawler","description":"Manages the catching, storage, and release of ocean fish in a trawler net, including timing-based collection while sleeping, overflow handling, and animation synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceantrawler"},{"id":"game-scripts/prefabs/pondfish","title":"Pondfish","description":"Generates fish and eel prefabs with lifecycle, cooking, and weight traits for in-game consumption and trade.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pondfish"},{"id":"game-scripts/prefabs/seeds","title":"Seeds","description":"Defines the \'seeds\' and \'seeds_cooked\' prefabs with associated components for use as raw or cooked food, bait, farm planting material, and ocean fishing lures.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/seeds"},{"id":"game-scripts/stategraphs/SGfishingnetvisualizer","title":"Sgfishingnetvisualizer","description":"Manages the visual state machine for the fishing net, coordinating animation and movement during casting, opening, retrieving, and final pickup phases.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGfishingnetvisualizer"},{"id":"game-scripts/stategraphs/SGoceanfish","title":"Sgoceanfish","description":"Defines the state machine for ocean-dwelling fish entities, handling behaviors such as breaching, biting fishing hooks, and exiting water.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGoceanfish"},{"id":"game-scripts/stategraphs/SGsquid","title":"Sgsquid","description":"Defines the state machine and state transitions for the Squid aquatic creature, handling movement, combat, fishing interactions, breathing, and amphibious transitions.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGsquid"},{"id":"game-scripts/stategraphs/SGwobster","title":"Sgwobster","description":"Manages state transitions and animations for the Wobster creature during ocean fishing interactions, including hook escape, launch, and movement states.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGwobster"},{"id":"game-scripts/components/sharkboimanager","title":"Sharkboimanager","description":"Manages the Sharkboi arena lifecycle including creation, shrinking, boss spawning, and fishing interactions during ocean winter events.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sharkboimanager"},{"id":"game-scripts/brains/squidbrain","title":"Squidbrain","description":"Controls AI behavior for squid entities, managing movement, combat, fishing interactions, and herd coordination.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/squidbrain"},{"id":"game-scripts/scenarios/tacklecontainer_fishing","title":"Tacklecontainer Fishing","description":"Populates a fishing tackle container with randomized fishing bobbers and lures upon creation.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/tacklecontainer_fishing"},{"id":"game-scripts/prefabs/tacklestation","title":"Tacklestation","description":"A crafting station prefab that enables players to learn and prototype fishing-related blueprints; it supports state persistence, burning, haunting, and loot generation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tacklestation"},{"id":"game-scripts/prefabs/trinkets","title":"Trinkets","description":"Generates prefabs for all trinket items in DST, configuring their physics, tags, components, and game mechanics (e.g., trading, bait, slingshot ammo, ocean fishing).","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trinkets"},{"id":"game-scripts/prefabs/trophyscale_fish","title":"Trophyscale Fish","description":"A weighable fish stand that holds and displays caught trophy fish, supports building/removal via actions, and handles item persistence across reloads and burn states.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trophyscale_fish"},{"id":"game-scripts/prefabs/twigs","title":"Twigs","description":"A multi-functional small item that serves as fuel, food, repair material, and ocean fishing tackle in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/twigs"},{"id":"game-scripts/brains/wobsterbrain","title":"Wobsterbrain","description":"AI controller for the Wobster entity that manages its behavior while fishing, including struggling when hooked, returning home during the day, and interacting with fishing lures.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wobsterbrain"}],"unlisted":false}}')}}]);